// Normalize incoming lead data from any source
// (web form, CRM, broker portal, etc.)
const body = $input.first().json.body || $input.first().json;

return [{
  json: {
    customer_id:   body.customer_id  || body.email || `LEAD-${Date.now()}`,
    first_name:    body.first_name   || body.name?.split(' ')[0] || '',
    last_name:     body.last_name    || body.name?.split(' ')[1] || '',
    email:         body.email        || '',
    phone:         body.phone        || '',
    segment:       body.segment      || body.company_size || 'Privat',
    lead_source:   body.source       || body.channel || 'web',
    product_interest: body.product   || body.interest || 'Unbekannt',
    company:       body.company      || '',
    annual_revenue: body.revenue     || null,
    employee_count: body.employees   || null,
    notes:         body.message      || '',
    received_at:   new Date().toISOString()
  }
}];

// Validate required fields before sending to agent
const lead = $input.first().json;
const errors = [];

if (!lead.customer_id) errors.push('customer_id missing');
if (!lead.email && !lead.phone) errors.push('no contact info');
if (!lead.product_interest) errors.push('no product interest');

return [{
  json: {
    ...lead,
    valid: errors.length === 0,
    validation_errors: errors
  }
}];

// Parse agent response and determine routing
const agent = $input.first().json;
const lead  = $('Validate Lead').first().json;

const score = agent.score ?? 0;
const confidence = agent.confidence ?? 0.5;

// Business rule: enterprise leads always get human review
const isEnterprise = lead.segment?.toLowerCase().includes('enterprise') ||
                     (lead.employee_count && lead.employee_count > 100);

let route;
if (isEnterprise || score >= 80) {
  route = 'human_review';
} else if (score >= 40) {
  route = 'automation';    // Sales sequence
} else {
  route = 'automation';    // Nurturing sequence
}

// Override: low confidence always needs human check
if (confidence < 0.5) route = 'human_review';

const urgency = score >= 70 ? 'high' : score >= 40 ? 'medium' : 'low';

return [{
  json: {
    // Original lead data
    ...lead,
    // Agent output
    lead_score:  score,
    segment:     agent.segment || lead.segment,
    confidence:  confidence,
    reasoning:   agent.reasoning || '',
    // Routing decision
    route:       route,
    urgency:     urgency,
    // Webhook payload fields
    title:  `Lead ${score >= 70 ? 'Sales' : score >= 40 ? 'Nurturing' : 'Abgelehnt'} — Score ${score}`,
    detail: `${lead.segment || 'Privat'} · ${lead.lead_source} · ${lead.product_interest}`,
    agent_latency_ms: agent.latency_ms || null
  }
}];
